CustomFunction.Calculation:
// Executes the assembled query via ExecuteSQL using Evaluate to
// dynamically bind the stored parameter values.
// Returns "" if ExecuteSQL returns an error (result starting with "?").
Let
(
[
_sql = QueryToSQL ( query ) ;
_bindings = JSONGetElement ( query ; "bindings" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_bindingArgs = QueryBuildBindingArgs ( _bindings ; _bindingCount ; 0 ) ;
_exprBase = "ExecuteSQL ( " & Quote ( _sql ) & " ; " & Quote ( fieldSeparator ) & " ; " & Quote ( rowSeparator ) ;
_expr = _exprBase & If ( _bindingCount > 0 ; " ; " & _bindingArgs ; "" ) & " )" ;
_result = Evaluate ( _expr )
];
If ( Left ( _result ; 1 ) = "?" ; "" ; _result )
)
